def test_scorecard_roadmap_j_includes_live_windows_benign_baseline_gate():
    roadmap_j = next(item for item in scorecard.ROADMAPS if item.key == "J")
    profile_ids = [rule.profile_id for rule in roadmap_j.profiles]

