def test_preflight_claim_lock_helper_creates_atomic_claim_lock(tmp_path):
    claims_payload = {
        "claims": [
            {
                "claim_id": "claim-ready",
                "package_id": "pkg-ready",
                "claim_state": "ready_to_claim",
            },
            {
                "claim_id": "claim-agent",
                "package_id": "pkg-agent",
                "claim_state": "ready_to_claim",
            }
        ]
    }
    helper_path = tmp_path / "claim_lock_helper.ps1"
    helper_path.write_text(preflight_work_package.render_claim_lock_helper(claims_payload), encoding="utf-8")
    repo_root = Path(__file__).resolve().parents[2]

    first = subprocess.run(
        [
            "powershell",
            "-NoProfile",
            "-ExecutionPolicy",
            "Bypass",
            "-File",
            str(helper_path),
            "-ClaimId",
            "claim-ready",
            "-AgentId",
            "agent-a",
        ],
        cwd=repo_root,
        text=True,
        capture_output=True,
    )
    second = subprocess.run(
        [
            "powershell",
            "-NoProfile",
            "-ExecutionPolicy",
            "Bypass",
            "-File",
            str(helper_path),
            "-ClaimId",
            "claim-ready",
            "-AgentId",
            "agent-b",
        ],
        cwd=repo_root,
        text=True,
        capture_output=True,
    )
    unknown = subprocess.run(
        [
            "powershell",
            "-NoProfile",
            "-ExecutionPolicy",
            "Bypass",
            "-File",
            str(helper_path),
            "-ClaimId",
            "claim-missing",
            "-AgentId",
            "agent-c",
        ],
        cwd=repo_root,
        text=True,
        capture_output=True,
    )
    invalid_agent = subprocess.run(
        [
            "powershell",
            "-NoProfile",
            "-ExecutionPolicy",
            "Bypass",
            "-File",
            str(helper_path),
            "-ClaimId",
            "claim-agent",
            "-AgentId",
            "agent with spaces",
        ],
        cwd=repo_root,
        text=True,
        capture_output=True,
    )
    list_locks = subprocess.run(
        [
            "powershell",
            "-NoProfile",
            "-ExecutionPolicy",
            "Bypass",
            "-File",
            str(helper_path),
            "-List",
        ],
        cwd=repo_root,
        text=True,
        capture_output=True,
    )
    reset_without_force = subprocess.run(
        [
            "powershell",
            "-NoProfile",
            "-ExecutionPolicy",
            "Bypass",
            "-File",
            str(helper_path),
            "-ResetClaimId",
            "claim-ready",
        ],
        cwd=repo_root,
        text=True,
        capture_output=True,
    )
    reset = subprocess.run(
        [
            "powershell",
            "-NoProfile",
            "-ExecutionPolicy",
            "Bypass",
            "-File",
            str(helper_path),
            "-ResetClaimId",
            "claim-ready",
            "-Force",
        ],
        cwd=repo_root,
        text=True,
        capture_output=True,
    )
    reacquire = subprocess.run(
        [
            "powershell",
            "-NoProfile",
            "-ExecutionPolicy",
            "Bypass",
            "-File",
            str(helper_path),
            "-ClaimId",
            "claim-ready",
            "-AgentId",
            "agent-d",
        ],
        cwd=repo_root,
        text=True,
        capture_output=True,
    )

    lock_path = tmp_path / "claim_locks" / "claim-ready.claim-lock.json"
    lock = json.loads(lock_path.read_text(encoding="utf-8"))
    assert first.returncode == 0
    assert second.returncode == 3
    assert unknown.returncode == 2
    assert invalid_agent.returncode == 2
    assert "AgentId may only contain letters" in invalid_agent.stdout
    assert not (tmp_path / "claim_locks" / "claim-agent.claim-lock.json").exists()
    assert list_locks.returncode == 0
    assert '"claim_id"' in list_locks.stdout
    assert '"claim-ready"' in list_locks.stdout
    assert reset_without_force.returncode == 4
    assert reset.returncode == 0
    assert reacquire.returncode == 0
    assert lock["claim_id"] == "claim-ready"
    assert lock["agent_id"] == "agent-d"


def test_preflight_env_bundle_launcher_validate_only_checks_env_without_launch_guard(tmp_path):
    claims_payload = {
        "claims": [
            {
                "claim_id": "claim-env",
                "package_id": "pkg-env",
                "claim_state": "blocked_or_manual",
                "wave": 1,
                "resource_tags": ["operator-env"],
                "script_path": "pkg-env.ps1",
                "missing_effective_env": ["TAMANDUA_TEST_ENV_BUNDLE_VALUE"],
                "blocked_reasons": ["missing_effective_env"],
            }
        ]
    }
    launcher_path = tmp_path / "env_bundle_ready_claims_launcher.ps1"
    launcher_path.write_text(preflight_work_package.render_env_bundle_ready_claims_launcher(claims_payload), encoding="utf-8")
    (tmp_path / "claim_lock_helper.ps1").write_text("# placeholder for validate-only path guard\n", encoding="utf-8")
    (tmp_path / "env_unblock_queue.json").write_text(
        json.dumps(valid_env_unblock_queue_for(["TAMANDUA_TEST_ENV_BUNDLE_VALUE"], ["claim-env"]), indent=2)
        + "\n",
        encoding="utf-8",
    )
    repo_root = Path(__file__).resolve().parents[2]
    env = os.environ.copy()
    env.pop("TAMANDUA_TEST_ENV_BUNDLE_VALUE", None)
    env.pop("TAMANDUA_ALLOW_ENV_BUNDLE_CLAIMS_LAUNCH", None)

    missing = subprocess.run(
        [
            "powershell",
            "-NoProfile",
            "-ExecutionPolicy",
            "Bypass",
            "-File",
            str(launcher_path),
            "-ValidateOnly",
        ],
        cwd=repo_root,
        env=env,
        text=True,
        capture_output=True,
    )
    env["TAMANDUA_TEST_ENV_BUNDLE_VALUE"] = "real-value"
    valid = subprocess.run(
        [
            "powershell",
            "-NoProfile",
            "-ExecutionPolicy",
            "Bypass",
            "-File",
            str(launcher_path),
            "-ValidateOnly",
        ],
        cwd=repo_root,
        env=env,
        text=True,
        capture_output=True,
    )
    env["TAMANDUA_TEST_ENV_BUNDLE_VALUE"] = "<set-tamandua-test-env-bundle-value>"
    placeholder = subprocess.run(
        [
            "powershell",
            "-NoProfile",
            "-ExecutionPolicy",
            "Bypass",
            "-File",
            str(launcher_path),
            "-ValidateOnly",
        ],
        cwd=repo_root,
        env=env,
        text=True,
        capture_output=True,
    )

    assert missing.returncode != 0
    assert "Missing env bundle values: TAMANDUA_TEST_ENV_BUNDLE_VALUE" in (missing.stdout + missing.stderr)
    assert "Env bundle missing set commands:" in missing.stdout
    assert "$env:TAMANDUA_TEST_ENV_BUNDLE_VALUE = '<set-tamandua-test-env-bundle-value>'" in missing.stdout
    assert valid.returncode == 0
    assert "Env bundle current env present: 1/1" in valid.stdout
    assert "Env bundle current env missing: -" in valid.stdout
    assert "Env bundle validation passed. Ready claims after complete env bundle: claim-env" in valid.stdout
    assert placeholder.returncode != 0
    assert "Placeholder env bundle values must be replaced before launch: TAMANDUA_TEST_ENV_BUNDLE_VALUE" in (
        placeholder.stdout + placeholder.stderr
    )


