        '"recommended_owner_role":"operator-or-secret-holder","title":"Caldera",'
        '"required_env":["CALDERA_API_KEY","CALDERA_AGENT_PAW"],'
        '"expected_profile_ids":["caldera-api-shape-probe"],'
